class Solution {
    static class TreeNode {
        // 当前节点的字符值
        char val;
        // 左子节点
        TreeNode left;
        // 右子节点
        TreeNode right;

        TreeNode(char val) {
            this.val = val;
        }
    }

    private boolean buildOk;

    public String buildAfterDelete(String preorderStr, String inorderStr, char beDeletedNode) {
        // 先检查两个字符串的基础合法性
        if (!isValidString(preorderStr) || !isValidString(inorderStr)) {
            return "";
        }

        // 长度必须相同
        if (preorderStr.length() != inorderStr.length()) {
            return "";
        }

        // 节点值必须唯一
        if (!isUnique(preorderStr) || !isUnique(inorderStr)) {
            return "";
        }

        // 两个遍历字符串的节点集合必须完全相同
        if (!sameSet(preorderStr, inorderStr)) {
            return "";
        }

        // 记录每个字符在中序遍历中的位置，方便递归时快速定位根节点
        int[] inorderPos = new int[256];
        for (int i = 0; i < inorderPos.length; i++) {
            inorderPos[i] = -1;
        }
        for (int i = 0; i < inorderStr.length(); i++) {
            inorderPos[inorderStr.charAt(i)] = i;
        }

        buildOk = true;

        // 构造二叉树
        TreeNode root = buildTree(
            preorderStr,
            0,
            preorderStr.length() - 1,
            inorderStr,
            0,
            inorderStr.length() - 1,
            inorderPos
        );

        // 如果无法构造出合法二叉树，返回空串
        if (!buildOk || root == null) {
            return "";
        }

        // 删除指定节点
        deleteNode(root, beDeletedNode);

        // 生成后序遍历结果
        StringBuilder ans = new StringBuilder();
        postorder(root, ans);
        return ans.toString();
    }

    private boolean isValidString(String s) {
        // 长度必须在 2 到 26 之间
        if (s == null || s.length() < 2 || s.length() > 26) {
            return false;
        }

        // 所有字符都必须是大写字母
        for (int i = 0; i < s.length(); i++) {
            char ch = s.charAt(i);
            if (ch < 'A' || ch > 'Z') {
                return false;
            }
        }
        return true;
    }

    private boolean isUnique(String s) {
        // 使用布尔数组判断是否存在重复字符
        boolean[] seen = new boolean[256];
        for (int i = 0; i < s.length(); i++) {
            char ch = s.charAt(i);
            if (seen[ch]) {
                return false;
            }
            seen[ch] = true;
        }
        return true;
    }

    private boolean sameSet(String a, String b) {
        // 由于长度已相同，只要每个字符出现集合相同即可
        boolean[] seenA = new boolean[256];
        boolean[] seenB = new boolean[256];

        for (int i = 0; i < a.length(); i++) {
            seenA[a.charAt(i)] = true;
            seenB[b.charAt(i)] = true;
        }

        for (int i = 0; i < 256; i++) {
            if (seenA[i] != seenB[i]) {
                return false;
            }
        }
        return true;
    }

    private TreeNode buildTree(
        String preorder,
        int preL,
        int preR,
        String inorder,
        int inL,
        int inR,
        int[] inorderPos
    ) {
        // 空区间表示空子树
        if (preL > preR) {
            return null;
        }

        // 前序和中序区间长度必须一致
        if (preR - preL != inR - inL) {
            buildOk = false;
            return null;
        }

        // 前序区间第一个字符是当前子树根节点
        char rootVal = preorder.charAt(preL);

        // 根节点必须出现在当前中序区间内
        int mid = inorderPos[rootVal];
        if (mid < inL || mid > inR) {
            buildOk = false;
            return null;
        }

        // 根据中序位置计算左子树大小
        int leftSize = mid - inL;

        // 左子树大小不能超过当前前序区间剩余长度
        if (preL + leftSize > preR) {
            buildOk = false;
            return null;
        }

        TreeNode root = new TreeNode(rootVal);

        // 递归构造左子树
        root.left = buildTree(
            preorder,
            preL + 1,
            preL + leftSize,
            inorder,
            inL,
            mid - 1,
            inorderPos
        );

        // 递归构造右子树
        root.right = buildTree(
            preorder,
            preL + leftSize + 1,
            preR,
            inorder,
            mid + 1,
            inR,
            inorderPos
        );

        return root;
    }

    private void deleteNode(TreeNode root, char target) {
        // 待删除字符不是大写字母时，不进行删除
        if (target < 'A' || target > 'Z') {
            return;
        }

        // 根节点不能删除
        if (root.val == target) {
            return;
        }

        // 查找目标节点及其父节点
        TreeNode[] result = findParent(root, target);
        TreeNode parent = result[0];
        TreeNode node = result[1];

        // 找不到目标节点时，不进行删除
        if (node == null) {
            return;
        }

        // 判断目标节点是父节点的左孩子还是右孩子
        boolean isLeftChild = parent.left == node;

        // 叶子节点直接删除
        if (node.left == null && node.right == null) {
            if (isLeftChild) {
                parent.left = null;
            } else {
                parent.right = null;
            }
            return;
        }

        // 内部节点如果是左子节点，就把它的左子树挂到父节点左侧
        if (isLeftChild) {
            parent.left = node.left;
        }
        // 内部节点如果是右子节点，就把它的右子树挂到父节点右侧
        else {
            parent.right = node.right;
        }
    }

    private TreeNode[] findParent(TreeNode root, char target) {
        // 深度优先搜索目标节点，同时记录父节点
        Deque<TreeNode[]> stack = new ArrayDeque<>();
        stack.push(new TreeNode[]{null, root});

        while (!stack.isEmpty()) {
            TreeNode[] current = stack.pop();
            TreeNode parent = current[0];
            TreeNode node = current[1];

            if (node == null) {
                continue;
            }

            if (node.val == target) {
                return new TreeNode[]{parent, node};
            }

            stack.push(new TreeNode[]{node, node.right});
            stack.push(new TreeNode[]{node, node.left});
        }

        return new TreeNode[]{null, null};
    }

    private void postorder(TreeNode node, StringBuilder ans) {
        // 空节点不产生输出
        if (node == null) {
            return;
        }

        // 后序遍历顺序：左子树、右子树、根节点
        postorder(node.left, ans);
        postorder(node.right, ans);
        ans.append(node.val);
    }
}
