    }

private:
    bool isValidString(const string& s) {
        // 长度必须在 2 到 26 之间
        if ((int)s.size() < 2 || (int)s.size() > 26) {
            return false;
        }

        // 所有字符都必须是大写字母
        for (char ch : s) {
            if (ch < 'A' || ch > 'Z') {
                return false;
            }
        }
        return true;
    }

    bool isUnique(const string& s) {
        // 使用布尔数组判断是否存在重复字符
        vector<bool> seen(256, false);

        for (char ch : s) {
            unsigned char idx = (unsigned char)ch;
            if (seen[idx]) {
