        // 由于长度已相同，只要每个字符出现集合相同即可
        vector<bool> seenA(256, false);
        vector<bool> seenB(256, false);

        for (char ch : a) {
            seenA[(unsigned char)ch] = true;
        }
        for (char ch : b) {
            seenB[(unsigned char)ch] = true;
        }

        for (int i = 0; i < 256; i++) {
            if (seenA[i] != seenB[i]) {
                return false;
            }
        }
        return true;
    }

    TreeNode* buildTree(
        const string& preorder,
        int preL,
        int preR,
        const string& inorder,
        int inL,
        int inR,
        const vector<int>& inorderPos
    ) {
        // 空区间表示空子树
        if (preL > preR) {
            return nullptr;
        }

        // 前序和中序区间长度必须一致
        if (preR - preL != inR - inL) {
            buildOk = false;
            return nullptr;
        }

        // 前序区间第一个字符是当前子树根节点
        char rootVal = preorder[preL];

        // 根节点必须出现在当前中序区间内
        int mid = inorderPos[(unsigned char)rootVal];
        if (mid < inL || mid > inR) {
            buildOk = false;
            return nullptr;
        }

        // 根据中序位置计算左子树大小
        int leftSize = mid - inL;

        // 左子树大小不能超过当前前序区间剩余长度
        if (preL + leftSize > preR) {
            buildOk = false;
            return nullptr;
        }

        TreeNode* root = new TreeNode(rootVal);

        // 递归构造左子树
        root->left = buildTree(
            preorder,
            preL + 1,
            preL + leftSize,
            inorder,
            inL,
            mid - 1,
            inorderPos
        );

        // 递归构造右子树
        root->right = buildTree(
            preorder,
            preL + leftSize + 1,
            preR,
            inorder,
            mid + 1,
            inR,
            inorderPos
        );

        return root;
    }

    void deleteNode(TreeNode* root, char target) {
        // 待删除字符不是大写字母时，不进行删除
        if (target < 'A' || target > 'Z') {
            return;
        }

        // 根节点不能删除
        if (root->val == target) {
            return;
        }

        // 查找目标节点及其父节点
        pair<TreeNode*, TreeNode*> result = findParent(root, target);
        TreeNode* parent = result.first;
        TreeNode* node = result.second;

        // 找不到目标节点时，不进行删除
        if (node == nullptr) {
            return;
        }

        // 判断目标节点是父节点的左孩子还是右孩子
        bool isLeftChild = parent->left == node;

        // 叶子节点直接删除
        if (node->left == nullptr && node->right == nullptr) {
            if (isLeftChild) {
                parent->left = nullptr;
            } else {
                parent->right = nullptr;
            }
            clearTree(node);
            return;
        }

        // 内部节点如果是左子节点，就保留它的左子树，丢弃它和右子树
        if (isLeftChild) {
            TreeNode* keep = node->left;
            node->left = nullptr;
            clearTree(node);
            parent->left = keep;
        }
        // 内部节点如果是右子节点，就保留它的右子树，丢弃它和左子树
        else {
            TreeNode* keep = node->right;
            node->right = nullptr;
            clearTree(node);
            parent->right = keep;
        }
    }

    pair<TreeNode*, TreeNode*> findParent(TreeNode* root, char target) {
        // 深度优先搜索目标节点，同时记录父节点
        stack<pair<TreeNode*, TreeNode*>> st;
        st.push({nullptr, root});

        while (!st.empty()) {
            auto current = st.top();
            st.pop();

            TreeNode* parent = current.first;
            TreeNode* node = current.second;

            if (node == nullptr) {
                continue;
            }

            if (node->val == target) {
                return {parent, node};
            }

            st.push({node, node->right});
            st.push({node, node->left});
        }

        return {nullptr, nullptr};
    }

    void postorder(TreeNode* node, string& ans) {
        // 空节点不产生输出
        if (node == nullptr) {
            return;
        }

        // 后序遍历顺序：左子树、右子树、根节点
        postorder(node->left, ans);
        postorder(node->right, ans);
        ans.push_back(node->val);
    }

    void clearTree(TreeNode* node) {
        // 递归释放二叉树节点
        if (node == nullptr) {
            return;
        }

        clearTree(node->left);
        clearTree(node->right);
        delete node;
    }
};
